export interface SearchClient {
  query(term: string): Promise<string[]>;
}

export class ResultsLoader {
  private latestRequestId = 0;
  private results: string[] = [];
  private loading = false;

  constructor(private readonly client: SearchClient) {}

  async load(term: string): Promise<void> {
    const requestId = ++this.latestRequestId;
    this.loading = true;
    try {
      const rows = await this.client.query(term);
      if (requestId !== this.latestRequestId) {
        return;
      }
      this.results = rows;
    } finally {
      if (requestId === this.latestRequestId) {
        this.loading = false;
      }
    }
  }

  getResults(): readonly string[] {
    return this.results;
  }

  isLoading(): boolean {
    return this.loading;
  }
}
